blocks.value:
.scr-char {
  display: inline-block;
  width: 1em; text-align: center; /* 글리프 교체 시 폭 고정 */
  color: rgba(255,255,255,0.28);  /* 회전 중 글리프 */
}
.scr-char.on { color: #fff; }     /* 해독 확정 글자 */

var POOL = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#$%&@!?<>+=*";
// 시드 난수 — 같은 진행률이면 항상 같은 글리프
function rnd(seed) { var x = Math.sin(seed*127.1+311.7)*43758.5453; return x - Math.floor(x); }
function applyReveal(p) {
  var frame = Math.floor(p * 60);
  spans.forEach(function(s, i) {
    var lockP = 0.1 + (i / N) * 0.8;   // 좌→우 순차 잠금
    if (p >= lockP) { s.textContent = s.dataset.ch; s.classList.add("on"); }
    else s.textContent = POOL.charAt(Math.floor(rnd(i*91 + Math.floor(frame/2)*7) * POOL.length));
  });
}

.tw-cursor {
  display: inline-block; width: 3px; height: 1em;
  background: #fff; animation: blink 1s infinite;
  transition: opacity 400ms;
}
.tw-cursor.off { opacity: 0; animation: none; }
@keyframes blink { 0%,45% { opacity:1; } 50%,95% { opacity:0; } 100% { opacity:1; } }

function applyReveal(p) {
  var typeP = Math.min(1, p / 0.82);          // 0~82% 구간에 타이핑
  var count = Math.round(typeP * TEXT.length);
  textEl.textContent = TEXT.slice(0, count);   // slice 한 줄이 핵심
  cursor.classList.toggle("off", p > 0.92);    // 마지막에 커서 소멸
}

.slot {
  display: inline-block;
  width: 1em; height: 1em; overflow: hidden; /* 1글자 창 */
}
.slot-strip i { display: block; height: 1em; font-style: normal; }
.slot-strip i:last-child { color: #fff; } /* 마지막 칸 = 원본 글자 */

var K = 7; // 랜덤 글리프 6 + 원본 1
function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
function applyReveal(p) {
  strips.forEach(function(strip, i) {
    var local = clamp01((p - i * 0.055) / 0.5);  // 글자별 stagger
    strip.style.transform = "translateY(" + (-easeOutCubic(local) * (K - 1)) + "em)";
  });
}

.flap-row { display: flex; gap: 8px; perspective: 800px; }
.flap-cell {
  width: 1.35em; height: 1.5em; /* 고정폭 타일 */
  background: #161616; border-radius: 8px;
  position: relative;
}
.flap-cell::after { /* 스플릿 플랩 분할선 */
  content: ""; position: absolute; left: 0; right: 0;
  top: 50%; height: 1px; background: rgba(0,0,0,0.6);
}
.flap-cell.on { color: #ffd23f; } /* 확정 = 앰버 */

var F = 4; // 플립 횟수 (랜덤 3 → 원본 확정)
var t = local * F;
var k = Math.min(F - 1, Math.floor(t));
var frac = t - k;
// 전반: 이전 글리프가 0→90°로 접힘 / 후반: 다음 글리프가 90→0°로 펴짐
if (frac < 0.5) { angle = frac * 180; glyph = seq[k]; }
else { angle = (1 - frac) * 180; glyph = seq[k + 1]; }
cell.style.transform = "rotateX(" + angle + "deg)";

.roll-char { display: inline-block; height: 1.05em; overflow: hidden; }
.roll-top, .roll-bot {
  display: block; height: 1.05em;
  transition: transform 360ms cubic-bezier(0.76, 0, 0.24, 1);
}
.roll-bot { color: #8ab4ff; } /* 아래층 = 액센트 색 */
.roll-item.is-hover .roll-top,
.roll-item.is-hover .roll-bot { transform: translateY(-100%); }

// 글자별 transition-delay를 빌드 시점에 인라인으로
top.style.transitionDelay = (i * 24) + "ms";
bot.style.transitionDelay = (i * 24) + "ms";
// 호버는 클래스 토글 하나로
item.addEventListener("mouseenter", function() { item.classList.add("is-hover"); });
item.addEventListener("mouseleave", function() { item.classList.remove("is-hover"); });

.gl-layer {
  position: absolute; inset: 0;
  opacity: 0; mix-blend-mode: screen;
}
.gl-r { color: #ff3b5c; } /* 빨강 잔상 */
.gl-c { color: #22d3ee; } /* 시안 잔상 */

var BURSTS = [[0.08, 0.2], [0.36, 0.48], [0.66, 0.8]]; // 점멸 구간
var top = Math.floor(rnd(frame * 3.7 + li * 57) * 80);
var h = 6 + Math.floor(rnd(frame * 7.3 + li * 91) * 22);
var dx = (rnd(frame * 5.1 + li * 13) - 0.5) * 18;
layer.style.clipPath = "inset(" + top + "% 0 " + (100 - top - h) + "% 0)";
layer.style.transform = "translateX(" + dx + "px)";

.wave-char {
  display: inline-block;
  will-change: transform, opacity;
}

function applyReveal(p) {
  var phase = p * Math.PI * 7;          // 흐르는 위상
  var damp = 1 - easeOutQuad(p);        // 진폭 감쇠 1→0
  spans.forEach(function(s, i) {
    var y = Math.sin(phase - i * 0.55) * 26 * damp;
    s.style.opacity = clamp01(p * 6 - i * 0.18); // 순차 페이드 인
    s.style.transform = "translateY(" + y + "px)";
  });
}

.rot-mask {
  display: inline-block;
  height: 1.15em; overflow: hidden;
  vertical-align: bottom;
}
.rot-word { display: block; height: 1.15em; line-height: 1.15; color: #8ab4ff; }

var seg = Math.min(N - 0.0001, p * N); // 세그먼트 4개
var idx = Math.floor(seg);
var segP = seg - idx;
// 세그먼트의 70%는 정지, 마지막 30%에 한 칸 슬라이드
var slide = segP < 0.7 ? 0 : easeInOutCubic((segP - 0.7) / 0.3);
inner.style.transform = "translateY(" + (-(idx + slide) * 1.15) + "em)";
// 마지막 칸 = 첫 단어 클론 → p가 1에서 0으로 리셋돼도 이음새 없음

.er-line { min-height: 1.45em; } /* 지우는 동안 레이아웃 고정 */
.er-cursor {
  display: inline-block; width: 3px; height: 1em;
  background: #8ab4ff; animation: blink 1s infinite;
}

// 한 사이클 = type → hold → erase → type → hold → erase → blank
var SEGS = [
  ["type", 0, 0.00, 0.20], ["hold", 0, 0.20, 0.34], ["erase", 0, 0.34, 0.44],
  ["type", 1, 0.44, 0.66], ["hold", 1, 0.66, 0.84], ["erase", 1, 0.84, 0.94],
  ["blank", 0, 0.94, 1.00]
];
// type: segP×N자 출력 / erase: (1−segP)×N자 — 같은 slice 메커니즘
textEl.textContent = phrase.slice(0, count);

.nd-char {
  display: inline-block;
  width: 1ch; text-align: center; /* 회전 중 폭 고정 */
  font-variant-numeric: tabular-nums;
  color: rgba(255,255,255,0.35);
}
.nd-char.on { color: #fff; }
.nd-comma { width: 0.55ch; } /* 콤마는 처음부터 고정 */

var POOL = "0123456789#%$&"; // 숫자 + 기호 혼합 풀
spans.forEach(function(s, i) {
  var lockP = 0.08 + (i / N) * 0.74; // 큰 자리(왼쪽)부터 확정
  if (p >= lockP) { s.textContent = s.dataset.ch; s.classList.add("on"); }
  else if (s.dataset.ch !== ",")
    s.textContent = POOL.charAt(Math.floor(rnd(i*37 + Math.floor(frame/2)*11) * POOL.length));
});
suffix.style.opacity = clamp01((p - 0.88) / 0.12); // 마지막에 + 페이드 인
